import { verifyAdmin } from '@/app/lib/auth'
import { forbidden } from 'next/navigation'

export default async function AdminPage() {
  const { isAdmin, session } = await verifyAdmin()

  if (!session) {
    // No session at all — caller is unauthenticated, return 401
    // (In a fuller app you'd call unauthorized() for 401, but the spec
    // asks for 403 when the user is not an admin.)
    forbidden()
  }

  if (!isAdmin) {
    // Authenticated but lacking the admin role → 403 Forbidden
    forbidden()
  }

  return (
    <main style={{ maxWidth: 800, margin: '0 auto', padding: '2rem' }}>
      <h1>Admin Dashboard</h1>
      <p>Welcome, {session.name}!</p>

      <section style={{ marginTop: '2rem' }}>
        <h2>Overview</h2>
        <p>
          You are logged in as <strong>{session.name}</strong> (role:{' '}
          <strong>{session.role}</strong>).
        </p>
      </section>

      <section style={{ marginTop: '2rem' }}>
        <h2>Management Tools</h2>
        <ul>
          <li>User Management</li>
          <li>Site Settings</li>
          <li>Analytics</li>
        </ul>
      </section>
    </main>
  )
}
